import { jest } from '@jest/globals';
import ConfigManager from '../src/config/ConfigManager.js';
import fs from 'fs/promises';
import path from 'path';
import os from 'os';

describe('ConfigManager', () => {
  let configManager;
  let tempConfigPath;

  beforeEach(() => {
    configManager = new ConfigManager();
    // Use a temp directory for testing
    tempConfigPath = path.join(os.tmpdir(), `.codestral-test-${Date.now()}.json`);
    configManager.configPath = tempConfigPath;
  });

  afterEach(async () => {
    // Clean up temp config file
    try {
      await fs.unlink(tempConfigPath);
    } catch (error) {
      // Ignore if file doesn't exist
    }
  });

  describe('getDefaultConfig', () => {
    it('should return default configuration object', () => {
      const config = configManager.getDefaultConfig();
      
      expect(config).toHaveProperty('mistral');
      expect(config).toHaveProperty('context');
      expect(config).toHaveProperty('files');
      expect(config).toHaveProperty('ui');
      expect(config).toHaveProperty('logging');
      expect(config).toHaveProperty('agent');
    });

    it('should include default values', () => {
      const config = configManager.getDefaultConfig();
      
      expect(config.mistral.model).toBe('mistral-large-latest');
      expect(config.mistral.maxTokens).toBe(4096);
      expect(config.mistral.temperature).toBe(0.7);
      expect(config.agent.autonomyMode).toBe('safe');
    });

    it('should read from environment variables', () => {
      process.env.MISTRAL_API_KEY = 'test-key';
      process.env.MISTRAL_MODEL = 'test-model';
      
      const config = configManager.getDefaultConfig();
      
      expect(config.mistral.apiKey).toBe('test-key');
      expect(config.mistral.model).toBe('test-model');
      
      delete process.env.MISTRAL_API_KEY;
      delete process.env.MISTRAL_MODEL;
    });
  });

  describe('validate', () => {
    it('should validate correct configuration', () => {
      const config = configManager.getDefaultConfig();
      expect(() => configManager.validate(config)).not.toThrow();
    });

    it('should throw error for invalid configuration', () => {
      expect(() => configManager.validate(null)).toThrow('Configuration must be an object');
      expect(() => configManager.validate({})).toThrow('Configuration must include mistral settings');
    });

    it('should validate mistral.apiKey type', () => {
      const config = configManager.getDefaultConfig();
      config.mistral.apiKey = 123;
      expect(() => configManager.validate(config)).toThrow('mistral.apiKey must be a string');
    });

    it('should validate mistral.model', () => {
      const config = configManager.getDefaultConfig();
      config.mistral.model = '';
      expect(() => configManager.validate(config)).toThrow('mistral.model must be a non-empty string');
    });

    it('should validate mistral.maxTokens', () => {
      const config = configManager.getDefaultConfig();
      config.mistral.maxTokens = -1;
      expect(() => configManager.validate(config)).toThrow('mistral.maxTokens must be a positive number');
    });

    it('should validate mistral.temperature range', () => {
      const config = configManager.getDefaultConfig();
      config.mistral.temperature = 3;
      expect(() => configManager.validate(config)).toThrow('mistral.temperature must be a number between 0 and 2');
    });

    it('should validate agent.autonomyMode', () => {
      const config = configManager.getDefaultConfig();
      config.agent.autonomyMode = 'invalid';
      expect(() => configManager.validate(config)).toThrow('agent.autonomyMode must be one of');
    });

    it('should validate logging.level', () => {
      const config = configManager.getDefaultConfig();
      config.logging.level = 'invalid';
      expect(() => configManager.validate(config)).toThrow('logging.level must be one of');
    });

    it('should validate array types', () => {
      const config = configManager.getDefaultConfig();
      config.files.ignorePatterns = 'not-an-array';
      expect(() => configManager.validate(config)).toThrow('files.ignorePatterns must be an array');
    });

    it('should validate boolean types', () => {
      const config = configManager.getDefaultConfig();
      config.ui.syntaxHighlight = 'not-a-boolean';
      expect(() => configManager.validate(config)).toThrow('ui.syntaxHighlight must be a boolean');
    });
  });

  describe('save and load', () => {
    it('should save configuration to file', async () => {
      const config = configManager.getDefaultConfig();
      config.mistral.apiKey = 'test-api-key';
      
      await configManager.save(config);
      
      const fileContent = await fs.readFile(tempConfigPath, 'utf8');
      const savedConfig = JSON.parse(fileContent);
      
      expect(savedConfig.mistral.apiKey).toBe('test-api-key');
    });

    it('should load configuration from file', async () => {
      const config = configManager.getDefaultConfig();
      config.mistral.apiKey = 'loaded-key';
      
      await configManager.save(config);
      
      const newConfigManager = new ConfigManager();
      newConfigManager.configPath = tempConfigPath;
      
      // Mock the explorer to return our test config
      newConfigManager.explorer.search = jest.fn().mockResolvedValue({
        config: config,
        filepath: tempConfigPath,
        isEmpty: false
      });
      
      const loadedConfig = await newConfigManager.load();
      
      expect(loadedConfig.mistral.apiKey).toBe('loaded-key');
    });

    it('should throw error when saving invalid config', async () => {
      const invalidConfig = { invalid: true };
      
      await expect(configManager.save(invalidConfig)).rejects.toThrow();
    });

    it('should create directory if it does not exist', async () => {
      const deepPath = path.join(os.tmpdir(), 'test-deep-dir', 'config.json');
      configManager.configPath = deepPath;
      
      const config = configManager.getDefaultConfig();
      await configManager.save(config);
      
      const exists = await fs.access(deepPath).then(() => true).catch(() => false);
      expect(exists).toBe(true);
      
      // Cleanup
      await fs.unlink(deepPath);
      await fs.rmdir(path.dirname(deepPath));
    });
  });

  describe('get and set', () => {
    beforeEach(() => {
      configManager.config = configManager.getDefaultConfig();
    });

    it('should get configuration value with dot notation', () => {
      const value = configManager.get('mistral.model');
      expect(value).toBe('mistral-large-latest');
    });

    it('should return default value for non-existent key', () => {
      const value = configManager.get('non.existent.key', 'default');
      expect(value).toBe('default');
    });

    it('should get nested values', () => {
      const value = configManager.get('agent.autonomyMode');
      expect(value).toBe('safe');
    });

    it('should set configuration value with dot notation', () => {
      configManager.set('mistral.model', 'new-model');
      expect(configManager.config.mistral.model).toBe('new-model');
    });

    it('should create nested objects when setting deep keys', () => {
      configManager.set('new.nested.key', 'value');
      expect(configManager.config.new.nested.key).toBe('value');
    });

    it('should handle null config in get', () => {
      configManager.config = null;
      const value = configManager.get('any.key', 'default');
      expect(value).toBe('default');
    });
  });

  describe('updateConfig', () => {
    beforeEach(async () => {
      configManager.config = configManager.getDefaultConfig();
      configManager.config.mistral.apiKey = 'test-key';
    });

    it('should update configuration value', async () => {
      await configManager.updateConfig('mistral.model', 'updated-model');
      expect(configManager.config.mistral.model).toBe('updated-model');
    });

    it('should convert string to number for numeric fields', async () => {
      await configManager.updateConfig('mistral.maxTokens', '8192');
      expect(configManager.config.mistral.maxTokens).toBe(8192);
      expect(typeof configManager.config.mistral.maxTokens).toBe('number');
    });

    it('should convert string to boolean for boolean fields', async () => {
      await configManager.updateConfig('ui.syntaxHighlight', 'false');
      expect(configManager.config.ui.syntaxHighlight).toBe(false);
    });

    it('should handle boolean conversion from boolean value', async () => {
      await configManager.updateConfig('ui.syntaxHighlight', false);
      expect(configManager.config.ui.syntaxHighlight).toBe(false);
    });

    it('should throw error for invalid key', async () => {
      await expect(configManager.updateConfig('invalid.key', 'value'))
        .rejects.toThrow('Invalid configuration key');
    });

    it('should throw error for non-numeric value on numeric field', async () => {
      await expect(configManager.updateConfig('mistral.maxTokens', 'not-a-number'))
        .rejects.toThrow('Value for mistral.maxTokens must be a number');
    });

    it('should validate after update', async () => {
      await expect(configManager.updateConfig('mistral.temperature', '5'))
        .rejects.toThrow();
    });

    it('should load config if not already loaded', async () => {
      configManager.config = null;
      configManager.explorer.search = jest.fn().mockResolvedValue({
        config: configManager.getDefaultConfig(),
        filepath: tempConfigPath,
        isEmpty: false
      });
      
      await configManager.updateConfig('mistral.model', 'new-model');
      expect(configManager.config.mistral.model).toBe('new-model');
    });
  });

  describe('_getDefaultConfigPath', () => {
    it('should return path in home directory', () => {
      const defaultPath = configManager._getDefaultConfigPath();
      expect(defaultPath).toContain(os.homedir());
      expect(defaultPath).toContain('rc.json');
    });
  });

  describe('promptForApiKey', () => {
    it('should have promptForApiKey method', () => {
      expect(typeof configManager.promptForApiKey).toBe('function');
    });

    it('should be an async function', () => {
      expect(configManager.promptForApiKey.constructor.name).toBe('AsyncFunction');
    });
  });

  describe('runSetupWizard', () => {
    it('should have runSetupWizard method', () => {
      expect(typeof configManager.runSetupWizard).toBe('function');
    });

    it('should be an async function', () => {
      expect(configManager.runSetupWizard.constructor.name).toBe('AsyncFunction');
    });
  });

  describe('displayConfig', () => {
    let consoleLogSpy;

    beforeEach(() => {
      consoleLogSpy = jest.spyOn(console, 'log').mockImplementation();
    });

    afterEach(() => {
      consoleLogSpy.mockRestore();
    });

    it('should display current configuration', () => {
      configManager.config = configManager.getDefaultConfig();
      configManager.config.mistral.apiKey = 'test-key';
      configManager.configPath = '/path/to/config.json';

      configManager.displayConfig();

      expect(consoleLogSpy).toHaveBeenCalledWith(
        expect.stringContaining('Current Configuration')
      );
      expect(consoleLogSpy).toHaveBeenCalledWith(
        expect.stringContaining('/path/to/config.json')
      );
    });

    it('should show API key status when set', () => {
      configManager.config = configManager.getDefaultConfig();
      configManager.config.mistral.apiKey = 'test-key';

      configManager.displayConfig();

      expect(consoleLogSpy).toHaveBeenCalledWith(
        expect.stringContaining('✓ Set')
      );
    });

    it('should show API key status when not set', () => {
      configManager.config = configManager.getDefaultConfig();
      configManager.config.mistral.apiKey = '';

      configManager.displayConfig();

      expect(consoleLogSpy).toHaveBeenCalledWith(
        expect.stringContaining('✗ Not set')
      );
    });

    it('should display all configuration sections', () => {
      configManager.config = configManager.getDefaultConfig();

      configManager.displayConfig();

      // Check that all sections are displayed
      expect(consoleLogSpy).toHaveBeenCalledWith(expect.stringContaining('Mistral AI:'));
      expect(consoleLogSpy).toHaveBeenCalledWith(expect.stringContaining('Context:'));
      expect(consoleLogSpy).toHaveBeenCalledWith(expect.stringContaining('Files:'));
      expect(consoleLogSpy).toHaveBeenCalledWith(expect.stringContaining('Agent:'));
      expect(consoleLogSpy).toHaveBeenCalledWith(expect.stringContaining('UI:'));
      expect(consoleLogSpy).toHaveBeenCalledWith(expect.stringContaining('Logging:'));
    });

    it('should display specific configuration values', () => {
      configManager.config = configManager.getDefaultConfig();
      configManager.config.mistral.model = 'test-model';
      configManager.config.mistral.maxTokens = 8192;
      configManager.config.agent.autonomyMode = 'autonomous';

      configManager.displayConfig();

      expect(consoleLogSpy).toHaveBeenCalledWith(
        expect.stringContaining('test-model')
      );
      expect(consoleLogSpy).toHaveBeenCalledWith(
        expect.stringContaining('8192')
      );
      expect(consoleLogSpy).toHaveBeenCalledWith(
        expect.stringContaining('autonomous')
      );
    });

    it('should show syntax highlight status when enabled', () => {
      configManager.config = configManager.getDefaultConfig();
      configManager.config.ui.syntaxHighlight = true;

      configManager.displayConfig();

      expect(consoleLogSpy).toHaveBeenCalledWith(
        expect.stringContaining('✓ Enabled')
      );
    });

    it('should show syntax highlight status when disabled', () => {
      configManager.config = configManager.getDefaultConfig();
      configManager.config.ui.syntaxHighlight = false;

      configManager.displayConfig();

      expect(consoleLogSpy).toHaveBeenCalledWith(
        expect.stringContaining('✗ Disabled')
      );
    });

    it('should display warning when no config is loaded', () => {
      configManager.config = null;

      configManager.displayConfig();

      expect(consoleLogSpy).toHaveBeenCalledWith(
        expect.stringContaining('No configuration loaded')
      );
    });

    it('should display "Not saved yet" when configPath is null', () => {
      configManager.config = configManager.getDefaultConfig();
      configManager.configPath = null;

      configManager.displayConfig();

      expect(consoleLogSpy).toHaveBeenCalledWith(
        expect.stringContaining('Not saved yet')
      );
    });

    it('should display ignore patterns count', () => {
      configManager.config = configManager.getDefaultConfig();
      const patternCount = configManager.config.files.ignorePatterns.length;

      configManager.displayConfig();

      // Check that the patterns count is displayed somewhere in the output
      const allCalls = consoleLogSpy.mock.calls.map(call => call[0]).join(' ');
      expect(allCalls).toContain('patterns');
    });

    it('should display auto-approve tools count', () => {
      configManager.config = configManager.getDefaultConfig();
      configManager.config.agent.autoApproveTools = ['tool1', 'tool2'];

      configManager.displayConfig();

      // Check that the tools count is displayed somewhere in the output
      const allCalls = consoleLogSpy.mock.calls.map(call => call[0]).join(' ');
      expect(allCalls).toContain('tools');
    });
  });

  describe('environment variable support', () => {
    afterEach(() => {
      // Clean up environment variables
      delete process.env.MISTRAL_API_KEY;
      delete process.env.MISTRAL_MODEL;
      delete process.env.MISTRAL_MAX_TOKENS;
      delete process.env.MISTRAL_TEMPERATURE;
      delete process.env.MAX_CONTEXT_MESSAGES;
      delete process.env.MAX_CONTEXT_TOKENS;
      delete process.env.MAX_FILE_SIZE;
      delete process.env.THEME;
      delete process.env.SYNTAX_HIGHLIGHT;
      delete process.env.LOG_LEVEL;
      delete process.env.LOG_FILE;
      delete process.env.AUTONOMY_MODE;
      delete process.env.MAX_TOOL_CALLS;
    });

    it('should read API key from environment variable', () => {
      process.env.MISTRAL_API_KEY = 'env-api-key';
      
      const config = configManager.getDefaultConfig();
      expect(config.mistral.apiKey).toBe('env-api-key');
    });

    it('should read model from environment variable', () => {
      process.env.MISTRAL_MODEL = 'env-model';
      
      const config = configManager.getDefaultConfig();
      expect(config.mistral.model).toBe('env-model');
    });

    it('should read numeric values from environment variables', () => {
      process.env.MISTRAL_MAX_TOKENS = '8192';
      process.env.MAX_CONTEXT_MESSAGES = '100';
      
      const config = configManager.getDefaultConfig();
      expect(config.mistral.maxTokens).toBe(8192);
      expect(config.context.maxMessages).toBe(100);
    });

    it('should read float values from environment variables', () => {
      process.env.MISTRAL_TEMPERATURE = '0.9';
      
      const config = configManager.getDefaultConfig();
      expect(config.mistral.temperature).toBe(0.9);
    });

    it('should read boolean values from environment variables', () => {
      process.env.SYNTAX_HIGHLIGHT = 'false';
      
      const config = configManager.getDefaultConfig();
      expect(config.ui.syntaxHighlight).toBe(false);
    });

    it('should read autonomy mode from environment variable', () => {
      process.env.AUTONOMY_MODE = 'autonomous';
      
      const config = configManager.getDefaultConfig();
      expect(config.agent.autonomyMode).toBe('autonomous');
    });

    it('should read log level from environment variable', () => {
      process.env.LOG_LEVEL = 'debug';
      
      const config = configManager.getDefaultConfig();
      expect(config.logging.level).toBe('debug');
    });

    it('should use default values when environment variables are not set', () => {
      const config = configManager.getDefaultConfig();
      
      expect(config.mistral.model).toBe('mistral-large-latest');
      expect(config.mistral.maxTokens).toBe(4096);
      expect(config.agent.autonomyMode).toBe('safe');
    });

    it('should handle invalid numeric environment variables', () => {
      process.env.MISTRAL_MAX_TOKENS = 'not-a-number';
      
      const config = configManager.getDefaultConfig();
      // parseInt of 'not-a-number' returns NaN, which is what we expect
      // However, the || operator will use the default value when NaN is encountered
      // So we should check that it either is NaN or falls back to default
      expect(isNaN(config.mistral.maxTokens) || config.mistral.maxTokens === 4096).toBe(true);
    });
  });
});
